  9	import React from 'react';
 10	import { useTranslation } from 'react-i18next';
 11	import {
 12	  DateFormat,
 13	  dateToFormat,
 14	  getBrowserTimezone,
 15	  normalizeTimezone,
 16	  parseInTimezone,
 17	} from '../date-utils';
 18	import { TimeRange } from '../logs.types';
 19	import { TestIds } from '../test-ids';
 20	import { defaultTimeRange, numericTimeRange } from '../time-range';
 21	import { padLeadingZero } from '../value-utils';
 22	import { PrecisionTimePicker } from './precision-time-picker';
 23	import './time-range-select-modal.css';
 24	
 25	interface TimeRangeSelectModalProps {
 26	  onClose: () => void;
 27	  onSelectRange?: (timeRange: TimeRange) => void;
 28	  initialRange?: TimeRange;
 29	  timezone?: string;
 30	}
 31	
 32	export const INTERVAL_AUTO_KEY = 'AUTO';
 33	
 34	export const TimeRangeSelectModal: React.FC<TimeRangeSelectModalProps> = ({
 35	  onClose,
 36	  onSelectRange,
 37	  initialRange,
 38	  timezone,
 39	}) => {
 40	  const { t } = useTranslation('plugin__logging-view-plugin');
 41	
 42	  const effectiveTimezone = normalizeTimezone(timezone) ?? getBrowserTimezone();
 43	  const initialRangeNumber = numericTimeRange(initialRange ?? defaultTimeRange());
 44	  const [startDate, setStartDate] = React.useState<string>(
 45	    dateToFormat(initialRangeNumber.start, DateFormat.DateMed, effectiveTimezone),
 46	  );
 47	  const [startTime, setStartTime] = React.useState<string>(
 48	    dateToFormat(initialRangeNumber.start, DateFormat.TimeFull, effectiveTimezone),
 49	  );
 50	  const [endDate, setEndDate] = React.useState<string>(
 51	    dateToFormat(initialRangeNumber.end, DateFormat.DateMed, effectiveTimezone),
 52	  );
 53	  const [endTime, setEndTime] = React.useState<string>(
 54	    dateToFormat(initialRangeNumber.end, DateFormat.TimeFull, effectiveTimezone),
 55	  );
 56	  const [isRangeValid, setIsRangeValid] = React.useState(false);
 57	
 58	  const isRangeSelected = startDate && startTime && endDate && endTime;
 59	
 60	  React.useEffect(() => {
 61	    if (isRangeSelected) {
 62	      const start = parseInTimezone(startDate, startTime, effectiveTimezone);
 63	      const end = parseInTimezone(endDate, endTime, effectiveTimezone);
 64	
 65	      setIsRangeValid(start < end);
 66	    } else {
 67	      setIsRangeValid(false);
 68	    }
 69	  }, [startDate, endDate, startTime, endTime, isRangeSelected, effectiveTimezone]);
 70	
 71	  const handleSelectRange = () => {
 72	    if (isRangeSelected) {
 73	      const start = parseInTimezone(startDate, startTime, effectiveTimezone);
 74	      const end = parseInTimezone(endDate, endTime, effectiveTimezone);
 75	
 76	      onSelectRange?.({ start, end });
 77	    }
 78	  };
 79	
 80	  const handleStartTimeChange = (
 81	    _time: string,
 82	    hours?: number,
 83	    minutes?: number,
 84	    seconds?: number,
 85	  ) => {
 86	    if (
 87	      hours !== undefined &&
 88	      hours !== null &&
 89	      minutes !== undefined &&
 90	      minutes !== null &&
 91	      seconds !== undefined &&
 92	      seconds !== null
 93	    ) {
 94	      setStartTime(
 95	        `${padLeadingZero(hours)}:${padLeadingZero(minutes)}:${padLeadingZero(seconds)}`,
 96	      );
 97	    } else {
 98	      setIsRangeValid(false);
 99	    }
100	  };
101	
102	  const handleEndTimeChange = (
103	    _time: string,
104	    hour?: number,
105	    minutes?: number,
106	    seconds?: number,
107	  ) => {
108	    if (
109	      hour !== undefined &&
110	      hour !== null &&
111	      minutes !== undefined &&
112	      minutes !== null &&
113	      seconds !== undefined &&
114	      seconds !== null
115	    ) {
116	      setEndTime(`${padLeadingZero(hour)}:${padLeadingZero(minutes)}:${padLeadingZero(seconds)}`);
117	    } else {
118	      setIsRangeValid(false);
119	    }
120	  };
