123	   * we need to handle both cases until we can build different images per OCP version
124	   */
125	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
126	  const handleStartDateChange = (event: any, value: any) => {
127	    if (typeof event === 'string') {
128	      setStartDate(event);
129	    } else if (typeof value === 'string') {
130	      setStartDate(value);
131	    }
132	  };
