146	  return (
147	    <Modal
148	      id="date-time-picker-modal"
149	      className="modal-dialog lv-plugin__time-range-modal"
150	      variant={ModalVariant.small}
151	      title="Custom time range"
152	      position="top"
153	      isOpen
154	      onEscapePress={onClose}
155	      onClose={onClose}
156	      showClose={false}
157	      hasNoBodyWrapper={true}
158	      aria-label="date-time-picker-modal"
159	      data-test={TestIds.TimeRangeSelectModal}
160	      footer={
161	        <div className="lv-plugin__time-range-modal__footer">
162	          <Button
163	            key="confirm"
164	            variant="primary"
165	            onClick={handleSelectRange}
166	            isDisabled={!isRangeSelected || !isRangeValid}
167	            data-test={TestIds.TimeRangeDropdownSaveButton}
168	          >
169	            {t('Save')}
170	          </Button>
171	          <Button key="cancel" variant="secondary" onClick={onClose}>
172	            {t('Cancel')}
173	          </Button>
174	        </div>
175	      }
176	    >
177	      <ModalBoxBody
178	        className="lv-plugin__time-range-modal__body"
179	        data-test={TestIds.TimeRangeSelectModal}
180	      >
181	        <div>
182	          <label>{t('From')}</label>
183	          <div className="lv-plugin__time-range-modal__field">
184	            <DatePicker onChange={handleStartDateChange} value={startDate} />
185	            <PrecisionTimePicker time={startTime} onChange={handleStartTimeChange} />
186	          </div>
187	        </div>
188	        <div>
189	          <label>{t('To')}</label>
190	          <div className="lv-plugin__time-range-modal__field">
191	            <DatePicker onChange={handleEndDateChange} value={endDate} />
192	            <PrecisionTimePicker time={endTime} onChange={handleEndTimeChange} />
193	          </div>
194	          {!isRangeValid && (
195	            <Alert
196	              className="lv-plugin__time-range-modal__error"
197	              variant="danger"
198	              isInline
199	              isPlain
200	              title={t('Invalid date range')}
201	            />
202	          )}
203	        </div>
204	      </ModalBoxBody>
205	    </Modal>
206	  );
207	};

