 47	    dateToFormat(initialRangeNumber.start, DateFormat.DateMed, effectiveTimezone),
 48	  );
 49	  const [startTime, setStartTime] = React.useState<string>(
 50	    dateToFormat(initialRangeNumber.start, DateFormat.TimeFull, effectiveTimezone),
 51	  );
 52	  const [endDate, setEndDate] = React.useState<string>(
 53	    dateToFormat(initialRangeNumber.end, DateFormat.DateMed, effectiveTimezone),
 54	  );
 55	  const [endTime, setEndTime] = React.useState<string>(
 56	    dateToFormat(initialRangeNumber.end, DateFormat.TimeFull, effectiveTimezone),
 57	  );
 58	  const [isRangeValid, setIsRangeValid] = React.useState(false);
 59	
 60	  const isRangeSelected = startDate && startTime && endDate && endTime;
 61	
 62	  React.useEffect(() => {
 63	    if (isRangeSelected) {
 64	      const start = parseInTimezone(startDate, startTime, effectiveTimezone);
 65	      const end = parseInTimezone(endDate, endTime, effectiveTimezone);
 66	
 67	      setIsRangeValid(start < end);
 68	    } else {
 69	      setIsRangeValid(false);
 70	    }
 71	  }, [startDate, endDate, startTime, endTime, isRangeSelected, effectiveTimezone]);
 72	
 73	  const handleSelectRange = () => {
 74	    if (isRangeSelected) {
 75	      const start = parseInTimezone(startDate, startTime, effectiveTimezone);
 76	      const end = parseInTimezone(endDate, endTime, effectiveTimezone);
 77	
 78	      onSelectRange?.({ start, end });
 79	    }
 80	  };
 81	
 82	  const handleStartTimeChange = (
 83	    _time: string,
 84	    hours?: number,
 85	    minutes?: number,
 86	    seconds?: number,
 87	  ) => {
 88	    if (
 89	      hours !== undefined &&
 90	      hours !== null &&
 91	      minutes !== undefined &&
 92	      minutes !== null &&
 93	      seconds !== undefined &&
 94	      seconds !== null
 95	    ) {
 96	      setStartTime(
 97	        `${padLeadingZero(hours)}:${padLeadingZero(minutes)}:${padLeadingZero(seconds)}`,
 98	      );
 99	    } else {
100	      setIsRangeValid(false);
101	    }
102	  };
103	
104	  const handleEndTimeChange = (
105	    _time: string,
106	    hour?: number,
107	    minutes?: number,
108	    seconds?: number,
109	  ) => {
110	    if (
111	      hour !== undefined &&
112	      hour !== null &&
113	      minutes !== undefined &&
114	      minutes !== null &&
115	      seconds !== undefined &&
116	      seconds !== null
117	    ) {
118	      setEndTime(`${padLeadingZero(hour)}:${padLeadingZero(minutes)}:${padLeadingZero(seconds)}`);
119	    } else {
120	      setIsRangeValid(false);
121	    }
122	  };
123	
124	  /* As the patternfly version used in OCP 4.12-4.14 varies,
125	   * we need to handle both cases until we can build different images per OCP version
126	   */
127	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
128	  const handleStartDateChange = (event: any, value: any) => {
129	    if (typeof event === 'string') {
130	      setStartDate(event);
131	    } else if (typeof value === 'string') {
132	      setStartDate(value);
133	    }
134	  };
135	
136	  /* As the patternfly version used in OCP 4.12-4.14 varies,
137	   * we need to handle both cases until we can build different images per OCP version
138	   */
139	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
140	  const handleEndDateChange = (event: any, value: any) => {
141	    if (typeof event === 'string') {
142	      setEndDate(event);
143	    } else if (typeof value === 'string') {
144	      setEndDate(value);
145	    }
146	  };
147	
148	  return (
149	    <Modal
150	      id="date-time-picker-modal"
151	      className="modal-dialog lv-plugin__time-range-modal"
152	      variant={ModalVariant.small}
153	      position="top"
154	      isOpen
155	      onEscapePress={onClose}
156	      onClose={onClose}
157	      aria-label="date-time-picker-modal"
158	      data-test={TestIds.TimeRangeSelectModal}
159	    >
160	      <ModalHeader title="Custom time range" />
161	      <ModalBody
162	        className="lv-plugin__time-range-modal__body"
163	        data-test={TestIds.TimeRangeSelectModal}
164	      >
165	        <div>
166	          <label>{t('From')}</label>
167	          <div className="lv-plugin__time-range-modal__field">
168	            <DatePicker onChange={handleStartDateChange} value={startDate} />
169	            <PrecisionTimePicker time={startTime} onChange={handleStartTimeChange} />
170	          </div>
171	        </div>
172	        <div>
173	          <label>{t('To')}</label>
174	          <div className="lv-plugin__time-range-modal__field">
175	            <DatePicker onChange={handleEndDateChange} value={endDate} />
176	            <PrecisionTimePicker time={endTime} onChange={handleEndTimeChange} />
177	          </div>
178	          {!isRangeValid && (
179	            <Alert
180	              className="lv-plugin__time-range-modal__error"
181	              variant="danger"
182	              isInline
183	              isPlain
184	              title={t('Invalid date range')}
185	            />
186	          )}
187	        </div>
188	      </ModalBody>
189	      <ModalFooter>
190	        <div className="lv-plugin__time-range-modal__footer">
191	          <Button
192	            key="confirm"
193	            variant="primary"
194	            onClick={handleSelectRange}
195	            isDisabled={!isRangeSelected || !isRangeValid}
196	            data-test={TestIds.TimeRangeDropdownSaveButton}
197	          >
198	            {t('Save')}
199	          </Button>
200	          <Button key="cancel" variant="secondary" onClick={onClose}>
201	            {t('Cancel')}
202	          </Button>
203	        </div>
204	      </ModalFooter>
205	    </Modal>
206	  );
207	};
